const inputData = items[0].json;
const body = inputData.body || inputData;

// Get the binary data from the webhook
const binaryData = items[0].binary;

if (!binaryData || !binaryData.file) {
  return [{ json: { error: 'No image file received. Please upload a photo of your license disk.' } }];
}

// Pass the binary data through and build the prompt
const prompt = `You are a South African vehicle license disk reader. Extract ALL details from this license disk photo.

Return ONLY valid JSON with this exact structure:
{
  "registration": "registration number (e.g. GP 789-WXY or CA 456 789)",
  "make": "vehicle make (e.g. Toyota, Volkswagen, Ford, Nissan, Renault, Dacia, etc.)",
  "model": "vehicle model with variant if visible (e.g. Duster 1.5 dCi Dynamique)",
  "year": year as number (from date of first registration, e.g. 2019),
  "vin": "VIN/chassis number",
  "engineNumber": "engine number if visible",
  "color": "vehicle color if visible, otherwise empty string",
  "tareMass": tare mass in kg as number or null,
  "expiryDate": "license expiry date in YYYY-MM-DD format",
  "firstRegistrationDate": "date of first registration in YYYY-MM-DD format",
  "ownerName": "registered owner name if visible, otherwise empty string",
  "confidence": "high" or "medium" or "low"
}

Rules:
- Read ALL text carefully, license disks can be worn/faded
- Registration format is typically: XX 123-456 or XX 123 456 (province code + numbers)
- The make might say the manufacturer name (e.g. RENAULT, DACIA, TOYOTA)
- The model description often includes engine size (e.g. 1.5 DCI, 2.4 GD-6)
- Year comes from date of first registration
- If you cannot read a field clearly, use your best guess and set confidence to "medium" or "low"
- Return ONLY the JSON, no markdown, no explanation`;

return [{ json: { prompt }, binary: binaryData }];

const response = items[0].json;
let text = response.text || response.output || '';

// Handle different Gemini response formats
if (!text && response.candidates && response.candidates.length > 0) {
  const parts = response.candidates[0].content.parts;
  if (parts && parts.length > 0) text = parts[0].text;
}

if (!text) {
  return [{ json: { error: 'AI could not read the license disk. Please try a clearer photo.' } }];
}

// Clean up JSON from markdown code blocks
let jsonStr = text.trim();
if (jsonStr.startsWith('```')) {
  jsonStr = jsonStr.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
}

const firstBrace = jsonStr.indexOf('{');
if (firstBrace > 0) jsonStr = jsonStr.substring(firstBrace);
if (!jsonStr.endsWith('}')) {
  const lastBrace = jsonStr.lastIndexOf('}');
  if (lastBrace > 0) jsonStr = jsonStr.substring(0, lastBrace + 1);
}

try {
  const parsed = JSON.parse(jsonStr);
  return [{ json: {
    registration: parsed.registration || '',
    make: parsed.make || '',
    model: parsed.model || '',
    year: parsed.year || null,
    vin: parsed.vin || '',
    engineNumber: parsed.engineNumber || '',
    color: parsed.color || '',
    tareMass: parsed.tareMass || null,
    expiryDate: parsed.expiryDate || null,
    firstRegistrationDate: parsed.firstRegistrationDate || null,
    ownerName: parsed.ownerName || '',
    confidence: parsed.confidence || 'medium'
  } }];
} catch (e) {
  return [{ json: { error: 'AI response was not valid JSON. Please try again with a clearer photo.', raw: text } }];
}
